import { gpu } from '../gpu';
import { Tensor } from '../tensor';

const addShaderCode = `
@binding(0) @group(0) var<storage, read> a : array<f32>;
@binding(1) @group(0) var<storage, read> b : array<f32>;
@binding(2) @group(0) var<storage, read_write> c : array<f32>;

@compute @workgroup_size(64)
fn computeMain(@builtin(global_invocation_id) gid : vec3<u32>) {
  let idx = gid.x;
  if (idx >= arrayLength(&c)) {
    return;
  }
  c[idx] = a[idx] + b[idx];
}
`;

let addPipeline = null;

export function add(tensorA, tensorB) {
  if (tensorA.size !== tensorB.size) {
    throw new Error(`Tensor sizes must match for element-wise addition. Got ${tensorA.size} and ${tensorB.size}`);
  }

  const device = gpu.device;
  if (!device) {
    throw new Error('GPUDevice is not initialized.');
  }

  // Create pipeline if it doesn't exist
  if (!addPipeline) {
    const shaderModule = gpu.createShaderModule(addShaderCode, 'Tensor Add Shader');
    addPipeline = gpu.createComputePipeline(shaderModule, 'computeMain');
  }

  // Create output tensor
  const tensorC = new Tensor(tensorA.shape);

  // Create Bind Group
  const bindGroup = device.createBindGroup({
    layout: addPipeline.getBindGroupLayout(0),
    entries: [
      { binding: 0, resource: { buffer: tensorA.buffer } },
      { binding: 1, resource: { buffer: tensorB.buffer } },
      { binding: 2, resource: { buffer: tensorC.buffer } },
    ],
  });

  // Encode commands
  const encoder = device.createCommandEncoder({ label: 'Add Encoder' });
  const pass = encoder.beginComputePass({ label: 'Add Compute Pass' });
  pass.setPipeline(addPipeline);
  pass.setBindGroup(0, bindGroup);
  
  const workgroupCount = Math.ceil(tensorA.size / 64);
  pass.dispatchWorkgroups(workgroupCount);
  pass.end();

  device.queue.submit([encoder.finish()]);

  return tensorC;
}
