class GPUContext {
  constructor() {
    this.device = null;
    this.adapter = null;
  }

  async init() {
    if (this.device) return this.device;

    if (!navigator.gpu) {
      throw new Error('WebGPU is not supported by this browser.');
    }

    this.adapter = await navigator.gpu.requestAdapter();
    if (!this.adapter) {
      throw new Error('No appropriate GPUAdapter found.');
    }

    this.device = await this.adapter.requestDevice();
    if (!this.device) {
      throw new Error('Failed to create GPUDevice.');
    }

    this.device.lost.then((info) => {
      console.warn(`WebGPU device lost: ${info.message}`);
      this.device = null;
    });

    return this.device;
  }

  createShaderModule(code, label = 'Shader Module') {
    if (!this.device) throw new Error('GPUDevice is not initialized. Call init() first.');
    return this.device.createShaderModule({
      label,
      code,
    });
  }

  createComputePipeline(shaderModule, entryPoint = 'computeMain', layout = 'auto', constants = {}) {
    if (!this.device) throw new Error('GPUDevice is not initialized. Call init() first.');
    return this.device.createComputePipeline({
      layout,
      compute: {
        module: shaderModule,
        entryPoint,
        constants,
      },
    });
  }
}

export const gpu = new GPUContext();
