import { gpu } from './gpu';

export class Tensor {
  constructor(shape, dataOrUsage = null, usage = null) {
    if (!gpu.device) {
      throw new Error('GPUDevice is not initialized. Call gpu.init() before instantiating Tensors.');
    }

    this.shape = shape;
    this.size = shape.reduce((a, b) => a * b, 1);
    this.byteLength = this.size * Float32Array.BYTES_PER_ELEMENT;

    const defaultUsage = GPUBufferUsage.STORAGE | GPUBufferUsage.COPY_SRC | GPUBufferUsage.COPY_DST;

    if (dataOrUsage instanceof Float32Array) {
      this.usage = usage !== null ? usage : defaultUsage;
      this.buffer = gpu.device.createBuffer({
        label: 'Tensor Buffer',
        size: this.byteLength,
        usage: this.usage,
        mappedAtCreation: true,
      });
      new Float32Array(this.buffer.getMappedRange()).set(dataOrUsage);
      this.buffer.unmap();
    } else {
      this.usage = typeof dataOrUsage === 'number' ? dataOrUsage : defaultUsage;
      this.buffer = gpu.device.createBuffer({
        label: 'Tensor Buffer',
        size: this.byteLength,
        usage: this.usage,
      });
    }
  }

  async data() {
    if (!gpu.device) throw new Error('GPUDevice is not initialized.');

    const readBuffer = gpu.device.createBuffer({
      label: 'Tensor Readback Buffer',
      size: this.byteLength,
      usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ,
    });

    const encoder = gpu.device.createCommandEncoder();
    encoder.copyBufferToBuffer(this.buffer, 0, readBuffer, 0, this.byteLength);
    gpu.device.queue.submit([encoder.finish()]);

    await readBuffer.mapAsync(GPUMapMode.READ);
    const copy = new Float32Array(readBuffer.getMappedRange()).slice();
    readBuffer.unmap();
    readBuffer.destroy();

    return copy;
  }

  destroy() {
    if (this.buffer) {
      this.buffer.destroy();
      this.buffer = null;
    }
  }
}
