import { gpu } from '../gpu';
import { Tensor } from '../tensor';

const matmulShaderCode = `
struct Uniforms {
  M: u32,
  K: u32,
  N: u32,
}

@binding(0) @group(0) var<uniform> uniforms : Uniforms;
@binding(1) @group(0) var<storage, read> a : array<f32>;
@binding(2) @group(0) var<storage, read> b : array<f32>;
@binding(3) @group(0) var<storage, read_write> c : array<f32>;

@compute @workgroup_size(16, 16)
fn computeMain(@builtin(global_invocation_id) gid : vec3<u32>) {
  let col = gid.x;
  let row = gid.y;
  
  if (row >= uniforms.M || col >= uniforms.N) {
    return;
  }
  
  var sum = 0.0;
  for (var i: u32 = 0; i < uniforms.K; i = i + 1) {
    let aIdx = row * uniforms.K + i;
    let bIdx = i * uniforms.N + col;
    sum = sum + a[aIdx] * b[bIdx];
  }
  
  let cIdx = row * uniforms.N + col;
  c[cIdx] = sum;
}
`;

let matmulPipeline = null;

export function matmul(tensorA, tensorB) {
  if (tensorA.shape.length !== 2 || tensorB.shape.length !== 2) {
    throw new Error('Tensors must be 2D for matrix multiplication.');
  }

  const [M, K] = tensorA.shape;
  const [K2, N] = tensorB.shape;

  if (K !== K2) {
    throw new Error(`Dimension mismatch: A columns (${K}) must match B rows (${K2}).`);
  }

  const device = gpu.device;
  if (!device) {
    throw new Error('GPUDevice is not initialized.');
  }

  if (!matmulPipeline) {
    const shaderModule = gpu.createShaderModule(matmulShaderCode, 'Matmul Shader');
    matmulPipeline = gpu.createComputePipeline(shaderModule, 'computeMain');
  }

  // Create output tensor
  const tensorC = new Tensor([M, N]);

  // Create Uniform Buffer for dimensions
  const uniformData = new Uint32Array([M, K, N, 0]); // aligned to 16 bytes
  const uniformBuffer = device.createBuffer({
    label: 'Matmul Uniform Buffer',
    size: uniformData.byteLength,
    usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST,
  });
  device.queue.writeBuffer(uniformBuffer, 0, uniformData);

  // Create Bind Group
  const bindGroup = device.createBindGroup({
    layout: matmulPipeline.getBindGroupLayout(0),
    entries: [
      { binding: 0, resource: { buffer: uniformBuffer } },
      { binding: 1, resource: { buffer: tensorA.buffer } },
      { binding: 2, resource: { buffer: tensorB.buffer } },
      { binding: 3, resource: { buffer: tensorC.buffer } },
    ],
  });

  // Encode and Dispatch
  const encoder = device.createCommandEncoder({ label: 'Matmul Encoder' });
  const pass = encoder.beginComputePass({ label: 'Matmul Compute Pass' });
  pass.setPipeline(matmulPipeline);
  pass.setBindGroup(0, bindGroup);
  
  const workgroupsX = Math.ceil(N / 16);
  const workgroupsY = Math.ceil(M / 16);
  pass.dispatchWorkgroups(workgroupsX, workgroupsY);
  pass.end();

  device.queue.submit([encoder.finish()]);

  // Clean up uniform buffer after submit
  // Note: we can't destroy the uniform buffer immediately if it's still being read, 
  // but WebGPU command submission schedules the buffer reads.
  // We can destroy it after queue execution or let GC handle it. Since we created it, 
  // we will let the GC collect it or do a manual destroy after a map or queue.onSubmittedWorkDone,
  // but for simplicity we will just let GC handle it, or we can clean it up after a task.
  // Actually, keeping uniformBuffer in JS scope is fine.

  return tensorC;
}
